import { MakeLogicType, afterMount, connect, kea, listeners, path, selectors } from 'kea'
import { loaders } from 'kea-loaders'
import posthog from 'posthog-js'

import { projectLogic } from 'scenes/projectLogic'

import { customPropertyDefinitionsList } from 'products/customer_analytics/frontend/generated/api'
import type { CustomPropertyDefinitionApi } from 'products/customer_analytics/frontend/generated/api.schemas'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface accountCustomPropertyDefinitionsLogicValues {
    currentProjectId: number | null // projectLogic
    accountPropertyNames: string[]
    definitions: CustomPropertyDefinitionApi[]
    definitionsLoading: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface accountCustomPropertyDefinitionsLogicActions {
    loadCurrentProjectSuccess: (
        currentProject: null | import('~/types').ProjectType,
        payload?: any
    ) => {
        currentProject: null | import('~/types').ProjectType
        payload?: any
    } // projectLogic
    loadDefinitions: () => any
    loadDefinitionsFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadDefinitionsSuccess: (
        definitions: CustomPropertyDefinitionApi[],
        payload?: any
    ) => {
        definitions: CustomPropertyDefinitionApi[]
        payload?: any
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface accountCustomPropertyDefinitionsLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        accountPropertyNames: (definitions: CustomPropertyDefinitionApi[]) => string[]
    }
}

export type accountCustomPropertyDefinitionsLogicType = MakeLogicType<
    accountCustomPropertyDefinitionsLogicValues,
    accountCustomPropertyDefinitionsLogicActions,
    Record<string, any>,
    accountCustomPropertyDefinitionsLogicMeta
>

export const accountCustomPropertyDefinitionsLogic = kea<accountCustomPropertyDefinitionsLogicType>([
    path([
        'products',
        'workflows',
        'frontend',
        'Workflows',
        'hogflows',
        'registry',
        'triggers',
        'accountCustomPropertyDefinitionsLogic',
    ]),
    connect(() => ({
        values: [projectLogic, ['currentProjectId']],
        actions: [projectLogic, ['loadCurrentProjectSuccess']],
    })),
    loaders(({ values }) => ({
        definitions: [
            [] as CustomPropertyDefinitionApi[],
            {
                loadDefinitions: async (): Promise<CustomPropertyDefinitionApi[]> => {
                    if (!values.currentProjectId) {
                        return []
                    }
                    const response = await customPropertyDefinitionsList(String(values.currentProjectId))
                    return response.results
                },
            },
        ],
    })),
    selectors({
        accountPropertyNames: [
            (s) => [s.definitions],
            (definitions: CustomPropertyDefinitionApi[]): string[] =>
                definitions
                    .filter((definition) => (definition.target_type ?? 'account') === 'account')
                    .map((definition) => definition.name),
        ],
    }),
    listeners(({ actions }) => ({
        loadDefinitionsFailure: ({ error }) => {
            posthog.captureException(error, { scope: 'accountCustomPropertyDefinitionsLogic.load' })
        },
        // The logic can mount before the project resolves; retry the load once it does.
        loadCurrentProjectSuccess: () => {
            actions.loadDefinitions()
        },
    })),
    afterMount(({ actions }) => {
        actions.loadDefinitions()
    }),
])
